"use client"

import Link from "next/link"
import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Menu, X, Sparkles } from "lucide-react"

const navigation = [
  { name: "Home", href: "/" },
  { name: "About", href: "/about" },
  { name: "Services", href: "/services" },
  { name: "Team", href: "/team" },
  { name: "Projects", href: "/projects" },
  { name: "Careers", href: "/careers" },
  { name: "Contact", href: "/contact" },
]

// PERFECT LOGO COMPONENT (SVG Implementation)
const QuantixLogoIcon = ({ className }: { className?: string }) => (
  <svg 
    viewBox="0 0 100 120" 
    fill="none" 
    xmlns="http://www.w3.org/2000/svg" 
    className={className}
  >
    {/* Top Diamond (Slate/Black) */}
    <path 
      d="M50 5L85 25L50 45L15 25L50 5Z" 
      fill="#333333" 
    />
    <path 
      d="M50 12L75 25L50 38L25 25L50 12Z" 
      fill="white" 
      fillOpacity="0.2" 
    />

    {/* Middle Segment (Blue) */}
    <path 
      d="M15 35L50 55L85 35V45L50 65L15 45V35Z" 
      fill="#1FA2E1" 
    />
    
    {/* Bottom Segment (Blue) */}
    <path 
      d="M15 55L50 75L85 55V65L50 85L15 65V55Z" 
      fill="#1FA2E1" 
    />
  </svg>
)

export function Header() {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false)
  const [scrolled, setScrolled] = useState(false)
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 })

  // Parallax tracking
  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20)
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({
        x: (e.clientX / window.innerWidth - 0.5) * 20,
        y: (e.clientY / window.innerHeight - 0.5) * 20,
      })
    }

    window.addEventListener("scroll", handleScroll)
    window.addEventListener("mousemove", handleMouseMove)
    return () => {
      window.removeEventListener("scroll", handleScroll)
      window.removeEventListener("mousemove", handleMouseMove)
    }
  }, [])

  return (
    <header className={`sticky top-0 z-50 w-full transition-all duration-500 ${
      scrolled 
        ? "border-b border-border/40 bg-background/80 backdrop-blur-xl" 
        : "bg-transparent"
    }`}>
      <nav className="relative mx-auto flex max-w-7xl items-center justify-between px-4 py-4 lg:px-8">
        
        {/* PARALLAX BACKGROUND ELEMENT FOR HEADER */}
        <div 
          className="pointer-events-none absolute inset-0 -z-10 opacity-50 transition-transform duration-700 ease-out"
          style={{ transform: `translate3d(${mousePos.x}px, ${mousePos.y}px, 0)` }}
        >
           <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,#1FA2E10a_0%,transparent_70%)]" />
        </div>

        <div className="flex lg:flex-1">
          <Link href="/" className="-m-1.5 p-1.5 flex items-center gap-3 group">
            {/* The Precision Logo Icon */}
            <QuantixLogoIcon className="h-10 w-10 transition-transform duration-300 group-hover:scale-110 group-hover:rotate-3" />

            <div className="flex flex-col">
              <span className="text-xl font-medium tracking-tight text-foreground">
                Quantix<span className="font-bold">Labs</span>
              </span>
              <span className="text-[7px] font-extrabold uppercase tracking-[0.2em] text-muted-foreground/80">
                Turning Ideas into Intelligent Solutions
              </span>
            </div>
          </Link>
        </div>
        
        {/* Navigation & Buttons (Keep your existing logic) */}
        <div className="flex lg:hidden">
          <button onClick={() => setMobileMenuOpen(true)} className="p-2.5 text-foreground">
            <Menu className="h-6 w-6" />
          </button>
        </div>
        
        <div className="hidden lg:flex lg:gap-x-1">
          {navigation.map((item) => (
            <Link
              key={item.name}
              href={item.href}
              className="relative px-4 py-2 text-sm font-medium text-muted-foreground transition-all hover:text-[#1FA2E1] group"
            >
              {item.name}
              <span className="absolute bottom-0 left-1/2 h-0.5 w-0 bg-[#1FA2E1] transition-all group-hover:left-0 group-hover:w-full" />
            </Link>
          ))}
        </div>
        
        <div className="hidden lg:flex lg:flex-1 lg:justify-end">
          <Button size="sm" className="bg-[#1FA2E1] hover:bg-[#1890c9] shadow-lg shadow-blue-500/20" asChild>
            <Link href="/contact" className="gap-2">
              <Sparkles className="h-4 w-4" />
              Get Started
            </Link>
          </Button>
        </div>
      </nav>

      {/* Mobile Menu (Updated with Logo) */}
      {mobileMenuOpen && (
        <div className="fixed inset-0 z-50 bg-background p-6 lg:hidden">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
               <QuantixLogoIcon className="h-8 w-8" />
               <span className="font-bold">QuantixLabs</span>
            </div>
            <button onClick={() => setMobileMenuOpen(false)}><X /></button>
          </div>
          <div className="mt-8 space-y-4">
            {navigation.map((item) => (
              <Link key={item.name} href={item.href} className="block text-lg font-medium" onClick={() => setMobileMenuOpen(false)}>
                {item.name}
              </Link>
            ))}
          </div>
        </div>
      )}
    </header>
  )
}